// mm/src/pages/login.js
import React, { useMemo, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { tokenStore } from '../api/refresh';

const DEFAULT_LOGIN_URL = 'https://manuscriptmagic.fowkes.xyz/services/login.php';

function isValidEmail(email) {
  const v = String(email || '').trim();
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);
}

export default function LoginPage() {
  const nav = useNavigate();

  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [okMsg, setOkMsg] = useState('');
  const [showPw, setShowPw] = useState(false);

  const canSubmit = useMemo(() => {
    return isValidEmail(form.email) && String(form.password || '').length >= 1 && !loading;
  }, [form.email, form.password, loading]);

  const handleChange = (e) => {
    setError('');
    setOkMsg('');
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setOkMsg('');

    if (!isValidEmail(form.email)) {
      setError('Please enter a valid email.');
      return;
    }
    if (!form.password) {
      setError('Please enter your password.');
      return;
    }

    setLoading(true);
    try {
      const resp = await fetch(DEFAULT_LOGIN_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        // If your backend uses cookies, add:
        // credentials: 'include',
        body: JSON.stringify({
          email: form.email.trim(),
          password: form.password,
        }),
      });

      const data = await resp.json().catch(() => null);

      if (!resp.ok) {
        setError(data?.message || `Login failed (HTTP ${resp.status})`);
        return;
      }

      const success = data?.success === true || data?.Success === true;
      if (!success) {
        setError(data?.message || 'Login failed.');
        return;
      }

      // Accept multiple key styles
      const userId = data?.userId ?? data?.UserId ?? data?.userid ?? '';
      const accessToken = data?.accessToken ?? data?.AccessToken ?? '';
      const refreshToken = data?.refreshToken ?? data?.RenewalToken ?? data?.RefreshToken ?? '';

      if (!accessToken || !refreshToken) {
        setError('Login succeeded but backend did not return tokens.');
        return;
      }

      tokenStore.setTokens({ userId, accessToken, refreshToken });
      setOkMsg(data?.message || 'Login successful.');

      // Send them into the product
      nav('/workflow/start');
    } catch (err) {
      console.error(err);
      setError('Network error. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-slate-50 to-slate-100 flex items-center justify-center px-4 py-12">
      <div className="w-full max-w-xl bg-white border border-slate-200 rounded-2xl shadow-sm p-8">
        <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">Sign in</h1>
        <p className="mt-2 text-slate-500">Log in with your email and password.</p>

        <form onSubmit={handleSubmit} className="mt-8 space-y-5">
          <div>
            <label className="block text-sm font-medium text-slate-700">
              Email <span className="text-red-500">*</span>
            </label>
            <input
              name="email"
              type="email"
              value={form.email}
              onChange={handleChange}
              placeholder="you@email.com"
              className="mt-2 w-full border border-slate-200 rounded-md px-3 py-2 outline-none focus:ring-2 focus:ring-blue-200"
              autoComplete="email"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700">
              Password <span className="text-red-500">*</span>
            </label>
            <div className="mt-2 flex gap-2">
              <input
                name="password"
                type={showPw ? 'text' : 'password'}
                value={form.password}
                onChange={handleChange}
                placeholder="Your password"
                className="w-full border border-slate-200 rounded-md px-3 py-2 outline-none focus:ring-2 focus:ring-blue-200"
                autoComplete="current-password"
              />
              <button
                type="button"
                onClick={() => setShowPw((v) => !v)}
                className="px-3 py-2 border border-slate-200 rounded-md text-sm text-slate-700 bg-white hover:bg-slate-50"
              >
                {showPw ? 'Hide' : 'Show'}
              </button>
            </div>
          </div>

          {error ? <div className="text-sm text-red-600">{error}</div> : null}
          {okMsg ? <div className="text-sm text-emerald-700">{okMsg}</div> : null}

          <button
            type="submit"
            disabled={!canSubmit}
            className={[
              'w-full py-3 rounded-md text-white font-semibold',
              canSubmit ? 'bg-blue-600 hover:bg-blue-700' : 'bg-slate-300 cursor-not-allowed',
            ].join(' ')}
          >
            {loading ? 'Signing in…' : 'Sign in'}
          </button>

          <div className="text-sm text-slate-600 text-center">
            Don’t have an account?{' '}
            <Link to="/register" className="text-blue-700 hover:underline">
              Create one
            </Link>
          </div>
        </form>
      </div>
    </div>
  );
}
